# Drop table and storage folder if exists
from py4j.protocol import Py4JJavaError

spark.sql(f"""DROP TABLE IF EXISTS {db_notebookname}.{db_tablename}""")

try:
    raw_output_path = f"abfss://{destination_container}@{destination_storage}.dfs.core.windows.net/{destination_path}/{db_tablename}"
    mssparkutils.fs.rm(raw_output_path,recurse=True)

    print("Delete successful")

except Py4JJavaError as error :
    if 'org.apache.hadoop.fs.PathNotFoundException' in str (error.java_exception):
        print("No such file or directory")

# Create a temporary view
# As per Task 13812 we are only loading latest 2 loads based on loadDate (User Story 13812)
df_silver = spark.sql(f"""
                        SELECT raSimulationSetOutputLabelId, raSimulationSetOutputValueHashKey, SimNumber, Date, Period, Value, date_format(CDC_LoadDate,'yyyy-MM-dd HH:mm:ss.SSSSSS') AS LoadDate
                        FROM {Bronze_notebookname}.{db_tablename}
                        WHERE CDC_CurrentFlag = 1
                        AND CDC_LoadDate in (SELECT DISTINCT CDC_LoadDate FROM {Bronze_notebookname}.{db_tablename}
                                                ORDER BY CDC_LoadDate DESC
                                                LIMIT 2);

